class Solution:

def has_eulerian_path(self, graph):
	heap = []
	in_degree = {}
	scc = {}
	for node in graph:
		for neighbor in node[1]:
			in_degree[neighbor] = in_degree.get(neighbor, 0) + 1
			if in_degree[neighbor] % 2 != 0:
				heap.append(neighbor)
			else:
				scc[neighbor] = node[0]
			if node[0] not in scc:
				scc[node[0]] = node[0]
	odd_count = 0
	for node in in_degree:
		if in_degree[node] % 2 != 0:
			odd_count += 1
	runtime_error = False
	for component in scc.values():
		in_degree_component = {}
		for node in component:
			in_degree_component[node] = in_degree.get(node, 0)
		odd_component = 0
		for node in in_degree_component:
			if in_degree_component[node] % 2 != 0:
				odd_component += 1
		if odd_component > 2 and len(component) > 1:
				runtime_error = True
			break
		if runtime_error:
			break
	return len(heap) <= 3 and not runtime_error

