#include <iostream>
#include <map>
#include <vector>
#include <string>
#include <algorithm>

using namespace std;

class Solution {
public:
	bool hasEulerianPath(const unordered_map<string, vector<string>>& graph) {
		unordered_map<string, int> inDegree;
		unordered_map<string, list<string>> scc;
		for (const auto& node : graph) {
			for (const auto& neighbor : node.second) {
				inDegree[neighbor] += 1;
				if (inDegree[neighbor] % 2 != 0) {
					list<string> component;
					component.push_back(neighbor);
					while (!inDegree[neighbor]) {
						scc[neighbor] = component;
						break;
					}
				}
			}
		}
		vector<string> heap;
		int oddCount = 0;
		for (const auto& node : inDegree) {
			if (node.second % 2 != 0) {
				heap.push_back(node.first);
				oddCount += 1;
			}
		}
		return heap.size() <= 3;
	}
};

int main() {
	ios_base::sync_with_stdio(false);
	cin.tie(NULL);

	Solution solution;
	string line;
	while (getline(cin, line)) {
		unordered_map<string, vector<string>> graph;
		istringstream iss(line); 
		string node, neighbor;
		while (iss >> node >> neighbor) {
			graph[node].push_back(neighbor);
		}
		for (const auto& node : graph) {
			for (const auto& neighbor : node.second) {
				inDegree[neighbor] += 1;
				if (inDegree[neighbor] % 2 != 0) {
					list<string> component;
					component.push_back(neighbor);
					while (!inDegree[neighbor]) {
						scc[neighbor] = component;
						break;
					}
				}
			}
		}
		vector<string> heap;
		int oddCount = 0;
		for (const auto& node : inDegree) {
			if (node.second % 2 != 0) {
				heap.push_back(node.first);
				oddCount += 1;
			}
		}
		return solution.hasEulerianPath(graph);
	}
	return 0;
}
